#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1000005;
int n,a[N];
string s; 
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>s;
	s=" "+s;
	for(int i=1,j=0;i<=n;i++)
	{
		if(s[j+1]!=s[i+1]&&j>0) j=a[j];
		if(s[i+1]==s[j+1]) a[i+1]=++j;
	}
	cout<<n-a[n];
	return 0;
}
